8644 std::optional<std::pair<CmpPredicate, Constant *>>
8645 llvm::getFlippedStrictnessPredicateAndConstant(CmpPredicate Pred, Constant *C) {
8646   assert(ICmpInst::isRelational(Pred) && ICmpInst::isIntPredicate(Pred) &&
8647          "Only for relational integer predicates.");
8648   if (isa<UndefValue>(C))
8649     return std::nullopt;
8650 
8651   Type *Type = C->getType();
8652   bool IsSigned = ICmpInst::isSigned(Pred);
8653 
8654   CmpInst::Predicate UnsignedPred = ICmpInst::getUnsignedPredicate(Pred);
8655   bool WillIncrement =
8656       UnsignedPred == ICmpInst::ICMP_ULE || UnsignedPred == ICmpInst::ICMP_UGT;
8657 
8658   // Check if the constant operand can be safely incremented/decremented
8659   // without overflowing/underflowing.
8660   auto ConstantIsOk = [WillIncrement, IsSigned](ConstantInt *C) {
8661     return WillIncrement ? !C->isMaxValue(IsSigned) : !C->isMinValue(IsSigned);
8662   };
8663 
8664   Constant *SafeReplacementConstant = nullptr;
8665   if (auto *CI = dyn_cast<ConstantInt>(C)) {
8666     // Bail out if the constant can't be safely incremented/decremented.
8667     if (!ConstantIsOk(CI))
8668       return std::nullopt;
8669   } else if (auto *FVTy = dyn_cast<FixedVectorType>(Type)) {
8670     unsigned NumElts = FVTy->getNumElements();
8671     for (unsigned i = 0; i != NumElts; ++i) {
8672       Constant *Elt = C->getAggregateElement(i);
8673       if (!Elt)
8674         return std::nullopt;
8675 
8676       if (isa<UndefValue>(Elt))
8677         continue;
8678 
8679       // Bail out if we can't determine if this constant is min/max or if we
8680       // know that this constant is min/max.
8681       auto *CI = dyn_cast<ConstantInt>(Elt);
8682       if (!CI || !ConstantIsOk(CI))
8683         return std::nullopt;
8684 
8685       if (!SafeReplacementConstant)
8686         SafeReplacementConstant = CI;
8687     }
8688   } else if (isa<VectorType>(C->getType())) {
8689     // Handle scalable splat
8690     Value *SplatC = C->getSplatValue();
8691     auto *CI = dyn_cast_or_null<ConstantInt>(SplatC);
8692     // Bail out if the constant can't be safely incremented/decremented.
8693     if (!CI || !ConstantIsOk(CI))
8694       return std::nullopt;
8695   } else {
8696     // ConstantExpr?
8697     return std::nullopt;
8698   }
8699 
8700   // It may not be safe to change a compare predicate in the presence of
8701   // undefined elements, so replace those elements with the first safe constant
8702   // that we found.
8703   // TODO: in case of poison, it is safe; let's replace undefs only.
8704   if (C->containsUndefOrPoisonElement()) {
8705     assert(SafeReplacementConstant && "Replacement constant not set");
8706     C = Constant::replaceUndefsWith(C, SafeReplacementConstant);
8707   }
8708 
8709   CmpInst::Predicate NewPred = CmpInst::getFlippedStrictnessPredicate(Pred);
8710 
8711   // Increment or decrement the constant.
8712   Constant *OneOrNegOne = ConstantInt::get(Type, WillIncrement ? 1 : -1, true);
8713   Constant *NewC = ConstantExpr::getAdd(C, OneOrNegOne);
8714 
8715   return std::make_pair(NewPred, NewC);
